"use client";

import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { DollarSign, ShoppingBag, Users, TrendingUp } from "lucide-react";

export default function AdminDashboardPage() {
    const supabase = createClient();

    // Analytics State
    const [stats, setStats] = useState({
        totalRevenue: 0,
        totalOrders: 0,
        weeklyOrders: 0,
        customers: 0
    });
    const [recentOrders, setRecentOrders] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        async function fetchAnalytics() {
            setLoading(true);

            // Fetch Orders
            const { data: orders } = await supabase
                .from("orders")
                .select("*")
                .order("created_at", { ascending: false });

            // Fetch Customers (Profiles)
            const { count: customerCount } = await supabase
                .from("profiles")
                .select("*", { count: 'exact', head: true });

            if (orders) {
                // Calculate total revenue from non-cancelled orders
                const revenue = orders
                    .filter(o => o.status !== 'cancelled')
                    .reduce((sum, order) => sum + parseFloat(order.total || 0), 0);

                // Get this week's orders
                const oneWeekAgo = new Date();
                oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);
                const weekly = orders.filter(o => new Date(o.created_at) > oneWeekAgo).length;

                setStats({
                    totalRevenue: revenue,
                    totalOrders: orders.length,
                    weeklyOrders: weekly,
                    customers: customerCount || 0
                });

                setRecentOrders(orders.slice(0, 5)); // Last 5 orders
            }

            setLoading(false);
        }

        fetchAnalytics();
    }, []);

    if (loading) return <div>Loading dashboard statistics...</div>;

    const statCards = [
        { title: "Total Revenue", value: `Γé╣${stats.totalRevenue.toLocaleString()}`, icon: DollarSign, color: "text-green-600", bg: "bg-green-100" },
        { title: "Total Orders", value: stats.totalOrders.toString(), icon: ShoppingBag, color: "text-blue-600", bg: "bg-blue-100" },
        { title: "New Orders (7d)", value: stats.weeklyOrders.toString(), icon: TrendingUp, color: "text-purple-600", bg: "bg-purple-100" },
        { title: "Registered Customers", value: stats.customers.toString(), icon: Users, color: "text-orange-600", bg: "bg-orange-100" },
    ];

    return (
        <div className="max-w-7xl mx-auto">
            <h1 className="text-3xl font-bold mb-8" style={{ fontFamily: "'Playfair Display', serif", color: "var(--forest-dark)" }}>
                Sales Dashboard
            </h1>

            {/* Stat Cards Matrix */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-10">
                {statCards.map((card, idx) => (
                    <div key={idx} className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm flex items-center gap-4">
                        <div className={`p-4 rounded-xl ${card.bg}`}>
                            <card.icon className={`w-8 h-8 ${card.color}`} strokeWidth={2} />
                        </div>
                        <div>
                            <p className="text-sm font-medium text-gray-500">{card.title}</p>
                            <p className="text-2xl font-bold text-gray-900 mt-1">{card.value}</p>
                        </div>
                    </div>
                ))}
            </div>

            {/* Recent Orders Overview */}
            <div className="bg-white rounded-2xl border border-gray-100 shadow-sm mb-10 overflow-hidden">
                <div className="px-6 py-5 border-b border-gray-100 flex justify-between items-center">
                    <h2 className="text-lg font-bold text-gray-900">Recent Orders</h2>
                    <a href="/admin/orders" className="text-sm text-[var(--forest)] font-medium hover:underline">View All</a>
                </div>
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-gray-50">
                            <th className="p-4 font-semibold text-gray-500 text-sm">Order #</th>
                            <th className="p-4 font-semibold text-gray-500 text-sm">Date</th>
                            <th className="p-4 font-semibold text-gray-500 text-sm">Status</th>
                            <th className="p-4 font-semibold text-gray-500 text-sm text-right">Total</th>
                        </tr>
                    </thead>
                    <tbody>
                        {recentOrders.map((order) => (
                            <tr key={order.id} className="border-b border-gray-50 hover:bg-gray-50">
                                <td className="p-4 font-medium">{order.order_number}</td>
                                <td className="p-4 text-sm text-gray-600">{new Date(order.created_at).toLocaleDateString()}</td>
                                <td className="p-4">
                                    <span className={`px-2 py-1 rounded-full text-xs font-semibold uppercase ${order.status === 'delivered' ? 'bg-green-100 text-green-700' :
                                            order.status === 'shipped' ? 'bg-blue-100 text-blue-700' :
                                                order.status === 'processing' ? 'bg-yellow-100 text-yellow-700' :
                                                    order.status === 'cancelled' ? 'bg-red-100 text-red-700' :
                                                        'bg-gray-100 text-gray-700'
                                        }`}>
                                        {order.status || 'pending'}
                                    </span>
                                </td>
                                <td className="p-4 font-bold text-right">Γé╣{parseFloat(order.total).toFixed(2)}</td>
                            </tr>
                        ))}
                        {recentOrders.length === 0 && (
                            <tr><td colSpan={4} className="p-8 text-center text-gray-500">No recent orders.</td></tr>
                        )}
                    </tbody>
                </table>
            </div>

            {/* Future Placeholder for Recharts / Graph */}
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
                <h2 className="text-lg font-bold text-gray-900 mb-4">Revenue Over Time</h2>
                <div className="h-64 rounded-xl flex items-center justify-center bg-gray-50 border border-dashed border-gray-200">
                    <p className="text-gray-400 font-medium">Chart Visualization Coming in Phase 2</p>
                </div>
            </div>
        </div>
    );
}

