"use client";

import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { toast } from "react-hot-toast";

export default function AdminFeedbackPage() {
    const [tickets, setTickets] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [replyingTo, setReplyingTo] = useState<string | null>(null);
    const [replyDraft, setReplyDraft] = useState("");
    const supabase = createClient();

    const fetchTickets = async () => {
        setLoading(true);
        const { data, error } = await supabase
            .from("support_tickets")
            .select(`*, profiles:user_id(email)`) // Join to get user email if they were logged in
            .order("created_at", { ascending: false });

        if (data) setTickets(data);
        if (error) toast.error("Failed to load tickets");
        setLoading(false);
    };

    useEffect(() => {
        fetchTickets();
    }, []);

    const handleSendReply = async (ticket: any) => {
        if (!replyDraft.trim()) return toast.error("Reply cannot be empty!");

        // 1. Save reply to DB and update status
        const { error } = await supabase
            .from("support_tickets")
            .update({
                admin_reply: replyDraft,
                status: 'replied'
            })
            .eq("id", ticket.id);

        if (error) {
            toast.error("Failed to save reply.");
            return;
        }

        // 2. Mock sending the email to the user
        // (In a real scenario, this would POST to a backend API route that uses Resend/Nodemailer)
        console.log(`Sending email to ${ticket.guest_email || ticket.profiles?.email}:`, replyDraft);
        toast.success("Reply saved and email sent securely!");

        setReplyingTo(null);
        setReplyDraft("");
        fetchTickets();
    };

    if (loading) return <div>Loading support tickets...</div>;

    return (
        <div className="max-w-5xl mx-auto">
            <h1 className="text-3xl font-bold mb-8" style={{ fontFamily: "'Playfair Display', serif", color: "var(--forest-dark)" }}>
                Support Tickets
            </h1>

            <div className="space-y-6">
                {tickets.map((ticket) => {
                    const customerEmail = ticket.profiles?.email || ticket.guest_email || "Unknown User";

                    return (
                        <div key={ticket.id} className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
                            <div className="px-6 py-4 bg-gray-50 border-b border-gray-100 flex justify-between items-center">
                                <div>
                                    <h3 className="font-bold text-gray-900">{ticket.subject}</h3>
                                    <p className="text-xs text-gray-500 mt-1">From: <strong>{customerEmail}</strong> ΓÇó {new Date(ticket.created_at).toLocaleString()}</p>
                                </div>
                                <span className={`px-3 py-1 text-xs font-bold uppercase rounded-full ${ticket.status === 'open' ? 'bg-yellow-100 text-yellow-700' :
                                        ticket.status === 'replied' ? 'bg-green-100 text-green-700' :
                                            'bg-gray-100 text-gray-700'
                                    }`}>
                                    {ticket.status}
                                </span>
                            </div>

                            <div className="p-6">
                                <p className="text-gray-700 whitespace-pre-wrap mb-6 bg-gray-50 p-4 rounded-xl">{ticket.message}</p>

                                {ticket.admin_reply ? (
                                    <div className="bg-green-50/50 p-4 rounded-xl border border-green-100">
                                        <h4 className="text-xs font-bold uppercase tracking-wider text-green-800 mb-2">Our Reply:</h4>
                                        <p className="text-green-900 whitespace-pre-wrap text-sm">{ticket.admin_reply}</p>
                                    </div>
                                ) : (
                                    <div>
                                        {replyingTo === ticket.id ? (
                                            <div className="space-y-4">
                                                <textarea
                                                    rows={4}
                                                    value={replyDraft}
                                                    onChange={(e) => setReplyDraft(e.target.value)}
                                                    className="w-full border border-gray-200 rounded-xl p-3 outline-none focus:ring-2 focus:ring-[var(--forest)]"
                                                    placeholder={`Write your reply to ${customerEmail}...`}
                                                />
                                                <div className="flex gap-2 justify-end">
                                                    <button onClick={() => setReplyingTo(null)} className="px-4 py-2 text-sm text-gray-500 hover:text-black">Cancel</button>
                                                    <button onClick={() => handleSendReply(ticket)} className="px-6 py-2 text-sm text-white font-medium rounded-lg" style={{ background: "var(--forest)" }}>
                                                        Send Email Reply
                                                    </button>
                                                </div>
                                            </div>
                                        ) : (
                                            <button
                                                onClick={() => { setReplyingTo(ticket.id); setReplyDraft(""); }}
                                                className="px-6 py-2 text-sm font-medium border rounded-lg transition-colors hover:bg-gray-50"
                                                style={{ borderColor: "var(--forest)", color: "var(--forest)" }}
                                            >
                                                Reply to Customer
                                            </button>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    );
                })}

                {tickets.length === 0 && (
                    <div className="text-center p-12 bg-white rounded-2xl border border-gray-100">
                        <p className="text-gray-500">Inbox zero! No support tickets have been submitted.</p>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import {
    LayoutDashboard,
    ShoppingCart,
    Users,
    MessageSquare,
    Settings,
    Tag,
    FileText,
    LogOut
} from "lucide-react";
import { auth } from "@/lib/firebase/config";
import { onAuthStateChanged, signOut } from "firebase/auth";
import { toast } from "react-hot-toast";

export default function AdminLayout({ children }: { children: React.ReactNode }) {
    const pathname = usePathname();
    const router = useRouter();
    const [isAuthorized, setIsAuthorized] = useState(false);

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, (user) => {
            if (!user) {
                router.push("/auth/login");
                return;
            }

            const adminDomain = process.env.NEXT_PUBLIC_ADMIN_DOMAIN || "@krishnanaturals.co.in";

            if (user.email && user.email.toLowerCase().endsWith(adminDomain.toLowerCase())) {
                setIsAuthorized(true);
            } else {
                toast.error("Access Denied. Admin privileges required.");
                router.push("/");
            }
        });

        return () => unsubscribe();
    }, [router]);

    const menuItems = [
        { name: "Dashboard", href: "/admin/dashboard", icon: LayoutDashboard },
        { name: "Orders", href: "/admin/orders", icon: ShoppingCart },
        { name: "Support Tickets", href: "/admin/feedback", icon: MessageSquare },
        { name: "Marketing & Offers", href: "/admin/marketing", icon: Tag },
        { name: "Blog Posts", href: "/admin/blog", icon: FileText },
        { name: "Settings", href: "/admin/settings", icon: Settings },
    ];

    if (!isAuthorized) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-gray-50" style={{ paddingTop: "4rem" }}>
                <p className="text-gray-500 font-medium animate-pulse">Verifying Admin Access...</p>
            </div>
        );
    }

    return (
        <div className="min-h-screen flex bg-gray-50 pt-[72px]">
            {/* Sidebar */}
            <aside className="w-64 bg-white border-r border-gray-200 flex flex-col fixed h-[calc(100vh-72px)] z-10">
                <div className="p-6 border-b border-gray-100">
                    <h2 className="text-xl font-bold uppercase tracking-widest text-center" style={{ color: "var(--forest-dark)" }}>
                        Admin Portal
                    </h2>
                </div>

                <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
                    {menuItems.map((item) => {
                        const isActive = pathname.startsWith(item.href);
                        return (
                            <Link
                                key={item.name}
                                href={item.href}
                                className={`flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-colors ${isActive
                                    ? "bg-[var(--forest)] text-white"
                                    : "text-gray-600 hover:bg-gray-50 hover:text-[var(--forest-dark)]"
                                    }`}
                            >
                                <item.icon size={18} />
                                {item.name}
                            </Link>
                        );
                    })}
                </nav>

                <div className="p-4 border-t border-gray-100">
                    <button
                        onClick={() => {
                            signOut(auth);
                            router.push("/");
                        }}
                        className="flex items-center gap-3 px-4 py-3 w-full rounded-xl font-medium text-red-600 hover:bg-red-50 transition-colors"
                    >
                        <LogOut size={18} />
                        Exit Admin
                    </button>
                </div>
            </aside>

            {/* Main Content Area */}
            <main className="flex-1 ml-64 p-8">
                {children}
            </main>
        </div>
    );
}

