"use client";

import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { toast } from "react-hot-toast";
import { Plus, Edit2, Trash2, X } from "lucide-react";

export default function AdminProductsPage() {
    const [products, setProducts] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [showForm, setShowForm] = useState(false);
    const [isEditing, setIsEditing] = useState(false);

    const [formData, setFormData] = useState({
        id: "",
        name: "",
        slug: "",
        price: 0,
        stock: 100,
        category: "general",
        description: "",
        is_active: true
    });

    const supabase = createClient();

    const fetchProducts = async () => {
        setLoading(true);
        const { data, error } = await supabase
            .from("products")
            .select("*")
            .order("created_at", { ascending: false });

        if (data) setProducts(data);
        if (error) toast.error("Failed to load products");
        setLoading(false);
    };

    useEffect(() => {
        fetchProducts();
    }, []);

    const resetForm = () => {
        setFormData({
            id: "", name: "", slug: "", price: 0, stock: 100, category: "general", description: "", is_active: true
        });
        setIsEditing(false);
        setShowForm(false);
    };

    const handleEdit = (product: any) => {
        setFormData(product);
        setIsEditing(true);
        setShowForm(true);
        window.scrollTo({ top: 0, behavior: "smooth" });
    };

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to delete this product?")) return;

        const { error } = await supabase.from("products").delete().eq("id", id);
        if (error) {
            toast.error("Failed to delete product");
        } else {
            toast.success("Product deleted successfully");
            fetchProducts();
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        const payload = {
            name: formData.name,
            slug: formData.slug,
            price: formData.price,
            stock: formData.stock,
            category: formData.category,
            description: formData.description,
            is_active: formData.is_active
        };

        if (isEditing) {
            const { error } = await supabase.from("products").update(payload).eq("id", formData.id);
            if (error) toast.error("Failed to update product: " + error.message);
            else toast.success("Product updated!");
        } else {
            const { error } = await supabase.from("products").insert([payload]);
            if (error) toast.error("Failed to create product: " + error.message);
            else toast.success("Product created!");
        }

        resetForm();
        fetchProducts();
    };

    if (loading && products.length === 0) return <div className="p-10 text-center">Loading Products...</div>;

    return (
        <div className="max-w-7xl mx-auto">
            <div className="flex justify-between items-center mb-8">
                <h1 className="text-3xl font-bold" style={{ fontFamily: "'Playfair Display', serif", color: "var(--forest-dark)" }}>
                    Inventory Management
                </h1>
                {!showForm && (
                    <button
                        onClick={() => setShowForm(true)}
                        className="flex items-center gap-2 px-4 py-2 rounded-xl text-white font-medium"
                        style={{ background: "var(--forest)" }}
                    >
                        <Plus size={18} /> Add Product
                    </button>
                )}
            </div>

            {/* Product Form */}
            {showForm && (
                <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm mb-8 relative">
                    <button onClick={resetForm} className="absolute top-6 right-6 text-gray-400 hover:text-gray-600">
                        <X size={24} />
                    </button>
                    <h2 className="text-xl font-bold mb-6 text-gray-900">{isEditing ? "Edit Product" : "New Product"}</h2>

                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Product Name</label>
                                <input required type="text" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} className="w-full px-3 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)]" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">URL Slug (e.g. pure-honey)</label>
                                <input required type="text" value={formData.slug} onChange={e => setFormData({ ...formData, slug: e.target.value.toLowerCase().replace(/ /g, '-') })} className="w-full px-3 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)]" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Price (Γé╣)</label>
                                <input required type="number" min="0" value={formData.price} onChange={e => setFormData({ ...formData, price: Number(e.target.value) })} className="w-full px-3 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)]" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Stock Quantity</label>
                                <input required type="number" min="0" value={formData.stock} onChange={e => setFormData({ ...formData, stock: Number(e.target.value) })} className="w-full px-3 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)]" />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                            <textarea rows={3} value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} className="w-full px-3 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)]"></textarea>
                        </div>

                        <div className="flex gap-4 pt-4">
                            <button type="submit" className="px-6 py-2 rounded-lg text-white font-medium" style={{ background: "var(--forest)" }}>
                                {isEditing ? "Update Product" : "Save Product"}
                            </button>
                            <button type="button" onClick={resetForm} className="px-6 py-2 rounded-lg bg-gray-100 text-gray-700 font-medium">Cancel</button>
                        </div>
                    </form>
                </div>
            )}

            {/* Product List */}
            <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-x-auto">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-gray-50 border-b border-gray-100">
                            <th className="p-4 font-semibold text-gray-500 text-sm">Product Name</th>
                            <th className="p-4 font-semibold text-gray-500 text-sm">Price</th>
                            <th className="p-4 font-semibold text-gray-500 text-sm">Stock</th>
                            <th className="p-4 font-semibold text-gray-500 text-sm">Status</th>
                            <th className="p-4 font-semibold text-gray-500 text-sm text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {products.map((product) => (
                            <tr key={product.id} className="border-b border-gray-50 hover:bg-gray-50">
                                <td className="p-4">
                                    <div className="font-medium text-gray-900">{product.name}</div>
                                    <div className="text-xs text-gray-500 truncate max-w-xs">{product.slug}</div>
                                </td>
                                <td className="p-4 font-medium">Γé╣{product.price}</td>
                                <td className="p-4">
                                    <span className={`px-2 py-1 rounded-full text-xs font-semibold ${product.stock > 0 ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                                        {product.stock} in stock
                                    </span>
                                </td>
                                <td className="p-4">
                                    <span className={`px-2 py-1 rounded-full text-xs font-semibold ${product.is_active ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-700'}`}>
                                        {product.is_active ? "Active" : "Draft"}
                                    </span>
                                </td>
                                <td className="p-4 text-right">
                                    <div className="flex justify-end gap-3">
                                        <button onClick={() => handleEdit(product)} className="text-blue-600 hover:text-blue-800 p-1">
                                            <Edit2 size={18} />
                                        </button>
                                        <button onClick={() => handleDelete(product.id)} className="text-red-500 hover:text-red-700 p-1">
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                        {products.length === 0 && !loading && (
                            <tr><td colSpan={5} className="p-8 text-center text-gray-500">No products found. Start by adding one.</td></tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Settings, ShieldAlert, CreditCard } from "lucide-react";
import { createClient } from "@/lib/supabase/client";
import { toast } from "react-hot-toast";

export default function AdminSettingsPage() {
    const supabase = createClient();
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);

    const [settings, setSettings] = useState({
        cod_enabled: true,
        maintenance_mode: false
    });

    // Fetch initial settings
    useEffect(() => {
        const fetchSettings = async () => {
            const { data, error } = await supabase.from('store_settings').select('*').eq('id', 1).single();
            if (data && !error) {
                setSettings({
                    cod_enabled: data.cod_enabled,
                    maintenance_mode: data.maintenance_mode
                });
            }
            setIsLoading(false);
        };
        fetchSettings();
    }, []);

    const toggleSetting = async (key: keyof typeof settings) => {
        setIsSaving(true);
        const newValue = !settings[key];

        // Optimistic UI Update
        setSettings(prev => ({ ...prev, [key]: newValue }));

        const { error } = await supabase
            .from('store_settings')
            .update({ [key]: newValue })
            .eq('id', 1);

        setIsSaving(false);

        if (error) {
            toast.error("Failed to update settings");
            console.error(error);
            // Revert state
            setSettings(prev => ({ ...prev, [key]: !newValue }));
        } else {
            toast.success(`Setting updated successfully`);
        }
    };

    if (isLoading) {
        return <div className="p-8 text-gray-500 animate-pulse">Loading settings...</div>;
    }

    return (
        <div className="max-w-5xl mx-auto">
