                            <p className="text-gray-500 mt-1">Allow customers to choose COD during checkout. If disabled, prepayments are forced.</p>
                        </div>
                    </div>

                    <label className={`relative inline-flex items-center cursor-pointer ${isSaving ? 'opacity-50 pointer-events-none' : ''}`}>
                        <input type="checkbox" className="sr-only peer" checked={settings.cod_enabled} onChange={() => toggleSetting('cod_enabled')} disabled={isSaving} />
                        <div className="w-14 h-7 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-0.5 after:left-[4px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-[var(--forest)]"></div>
                        <span className="ml-3 text-sm font-medium text-gray-900 w-16">
                            {settings.cod_enabled ? 'Enabled' : 'Disabled'}
                        </span>
                    </label>
                </div>

                {/* Maintenance Mode */}
                <div className="bg-white p-6 md:p-8 rounded-2xl border border-red-100 shadow-sm flex flex-col md:flex-row gap-6 justify-between items-start md:items-center">
                    <div className="flex gap-4 items-start">
                        <div className="p-3 bg-red-50 text-red-600 rounded-xl mt-1">
                            <ShieldAlert size={24} />
                        </div>
                        <div>
                            <h2 className="text-xl font-bold text-gray-900">Maintenance Mode</h2>
                            <p className="text-gray-500 mt-1">Temporarily take the store offline. Customers will see a "We'll be right back" banner.</p>
                        </div>
                    </div>
                    {/* Disabling maintenance mode UI for safety demo currently */}
                    <label className="relative inline-flex items-center cursor-not-allowed opacity-50">
                        <input type="checkbox" className="sr-only peer" disabled />
                        <div className="w-14 h-7 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-0.5 after:left-[4px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-red-500"></div>
                        <span className="ml-3 text-sm font-medium text-gray-900 w-16">Offline</span>
                    </label>
                </div>

                {/* Database Health */}
                <div className="bg-white p-6 md:p-8 rounded-2xl border border-gray-100 shadow-sm flex flex-col md:flex-row gap-6 justify-between items-start md:items-center">
