                            Operational
                        </span>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Mail, Lock, ArrowRight, Chrome } from "lucide-react";
import { signInWithGoogle, signInWithEmail, signUpWithEmail, sendMagicLink } from "@/lib/firebase/auth";
import { useRouter } from "next/navigation";
import toast from "react-hot-toast";

type Mode = "login" | "signup" | "magic";

export default function LoginPage() {
    const router = useRouter();
    const [mode, setMode] = useState<Mode>("login");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [loading, setLoading] = useState(false);
    const [magicSent, setMagicSent] = useState(false);

    const handleGoogleSignIn = async () => {
        setLoading(true);
        try {
            await signInWithGoogle();
            toast.success("Welcome to Krishna Naturals!");
            router.push("/");
        } catch (err: any) {
            toast.error(err.message || "Google sign-in failed");
        } finally {
            setLoading(false);
        }
    };

    const handleEmailAuth = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        try {
            if (mode === "magic") {
                await sendMagicLink(email);
                setMagicSent(true);
                toast.success("Magic link sent! Check your email.");
            } else if (mode === "signup") {
                try {
                    await signUpWithEmail(email, password);
                } catch (e: any) {
                    if (e.message.includes("check your email")) {
                        toast.success("Account created! Verify your email before logging in.", { duration: 6000 });
                        setMode("login");
                    } else {
                        throw e;
                    }
                }
            } else {
                await signInWithEmail(email, password);
                toast.success("Welcome back!");
                router.push("/");
            }
        } catch (err: any) {
            toast.error(err.message || "Authentication failed");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div
            className="min-h-screen flex items-center justify-center px-6"
            style={{ paddingTop: "5rem", background: "var(--cream)" }}
        >
            <motion.div
                initial={{ opacity: 0, y: 20, scale: 0.98 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
                className="w-full max-w-md mx-auto rounded-2xl p-8"
                style={{
                    background: "var(--white)",
                    boxShadow: "0 20px 60px rgba(0,0,0,0.06), 0 0 0 1px var(--border)",
                }}
            >
                {/* Logo */}
                <div className="text-center mb-8">
                    <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-2xl mx-auto mb-4" style={{ background: "var(--forest-muted)" }}>
                        ≡ƒì»
                    </div>
                    <h1 className="text-2xl font-bold" style={{ fontFamily: "'Playfair Display', serif", color: "var(--forest-dark)" }}>
                        {mode === "signup" ? "Create Account" : "Welcome Back"}
                    </h1>
                    <p className="text-sm mt-1.5" style={{ color: "var(--gray-400)" }}>
                        {mode === "signup" ? "Join the Krishna Naturals family" : "Sign in to your account"}
                    </p>
                </div>

                {/* Google */}
                <motion.button
                    whileHover={{ scale: 1.01 }}
                    whileTap={{ scale: 0.99 }}
                    onClick={handleGoogleSignIn}
                    disabled={loading}
                    className="w-full flex items-center justify-center gap-3 p-3 rounded-xl text-sm font-semibold cursor-pointer mb-6"
                    style={{ background: "var(--white)", color: "var(--gray-700)", border: "1px solid var(--border-strong)", transition: "all 0.2s" }}
                >
                    <Chrome size={17} />
                    Continue with Google
                </motion.button>

                {/* Divider */}
                <div className="flex items-center gap-4 mb-6">
                    <div className="flex-1 h-px" style={{ background: "var(--border)" }} />
                    <span className="text-[11px] font-medium uppercase tracking-wider" style={{ color: "var(--gray-300)" }}>or</span>
                    <div className="flex-1 h-px" style={{ background: "var(--border)" }} />
                </div>

                <AnimatePresence mode="wait">
                    {magicSent ? (
                        <motion.div key="sent" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-center py-10">
                            <span className="text-5xl block mb-4">≡ƒôº</span>
                            <h3 className="text-lg font-bold mb-2" style={{ color: "var(--forest-dark)" }}>Check your email</h3>
                            <p className="text-sm" style={{ color: "var(--gray-500)" }}>We sent a magic link to <strong>{email}</strong>.</p>
                        </motion.div>
                    ) : (
                        <motion.form key="form" onSubmit={handleEmailAuth}>
                            <div className="mb-4">
                                <label className="block text-xs font-semibold mb-1.5 uppercase tracking-wider" style={{ color: "var(--gray-500)" }}>Email</label>
                                <div className="relative">
                                    <Mail size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2" style={{ color: "var(--gray-400)" }} />
                                    <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} required placeholder="you@example.com"
                                        className="w-full pl-10 pr-4 py-3 rounded-xl text-sm outline-none"
                                        style={{ background: "var(--gray-50)", border: "1px solid var(--border)", color: "var(--gray-800)", transition: "border-color 0.2s" }}
                                        onFocus={(e) => { e.currentTarget.style.borderColor = "var(--gold)"; }}
                                        onBlur={(e) => { e.currentTarget.style.borderColor = "var(--border)"; }}
                                    />
                                </div>
                            </div>
                            {mode !== "magic" && (
                                <div className="mb-6">
                                    <label className="block text-xs font-semibold mb-1.5 uppercase tracking-wider" style={{ color: "var(--gray-500)" }}>Password</label>
                                    <div className="relative">
                                        <Lock size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2" style={{ color: "var(--gray-400)" }} />
                                        <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                            className="w-full pl-10 pr-4 py-3 rounded-xl text-sm outline-none"
                                            style={{ background: "var(--gray-50)", border: "1px solid var(--border)", color: "var(--gray-800)", transition: "border-color 0.2s" }}
                                            onFocus={(e) => { e.currentTarget.style.borderColor = "var(--gold)"; }}
                                            onBlur={(e) => { e.currentTarget.style.borderColor = "var(--border)"; }}
                                        />
                                    </div>
                                </div>
                            )}
                            <motion.button whileHover={{ scale: 1.01 }} whileTap={{ scale: 0.99 }} type="submit" disabled={loading}
                                className="w-full btn btn-primary mb-4" style={{ padding: "0.875rem", fontSize: "0.9375rem" }}>
                                {loading ? "Please wait..." : mode === "magic" ? "Send Magic Link" : mode === "signup" ? "Create Account" : "Sign In"}
                                {!loading && <ArrowRight size={15} />}
                            </motion.button>
                        </motion.form>
                    )}
                </AnimatePresence>

                {!magicSent && (
                    <div className="text-center space-y-2 mt-4">
                        {mode !== "magic" && (
                            <button onClick={() => setMode("magic")} className="text-sm font-medium block w-full cursor-pointer" style={{ color: "var(--gold-dark)", background: "none", border: "none" }}>
                                Γ£¿ Sign in with Magic Link (passwordless)
                            </button>
                        )}
                        {mode === "magic" && (
                            <button onClick={() => setMode("login")} className="text-sm font-medium block w-full cursor-pointer" style={{ color: "var(--gold-dark)", background: "none", border: "none" }}>
                                ΓåÉ Back to password login
                            </button>
                        )}
                        <button onClick={() => setMode(mode === "signup" ? "login" : "signup")} className="text-sm block w-full cursor-pointer" style={{ color: "var(--gray-400)", background: "none", border: "none" }}>
                            {mode === "signup" ? "Already have an account? Sign in" : "Don't have an account? Sign up"}
                        </button>
                    </div>
                )}
            </motion.div>
        </div>
    );
}

import { createClient } from "@/lib/supabase/client";
import { notFound } from "next/navigation";
import Image from "next/image";
import Link from "next/link";
import { Calendar, User, ArrowLeft } from "lucide-react";

export async function generateMetadata({ params }: { params: { slug: string } }) {
    const supabase = createClient();
    const { data: post } = await supabase
        .from("blog_posts")
        .select("title, excerpt, image_url")
        .eq("slug", params.slug)
        .single();

    if (!post) {
        return { title: "Post Not Found" };
    }

    return {
        title: `${post.title} ΓÇö Krishna Naturals Blog`,
        description: post.excerpt || `Read about ${post.title}`,
        openGraph: {
            title: post.title,
            description: post.excerpt,
            images: post.image_url ? [post.image_url] : [],
        }
    };
}

export default async function BlogPostPage({ params }: { params: { slug: string } }) {
    const supabase = createClient();

    const { data: post } = await supabase
        .from("blog_posts")
        .select(`
            id,
            title,
            content,
            image_url,
            published_at,
            author:author_id (
                name,
                image_url
            )
        `)
        .eq("slug", params.slug)
        .single();

    if (!post) {
        notFound();
    }

    const { data: relatedPosts } = await supabase
        .from("blog_posts")
        .select("title, excerpt, image_url, slug, published_at")
        .neq("id", post.id)
        .order("published_at", { ascending: false })
        .limit(3);

    // Provide fallback if author relationship fails or is null
    const authorName = Array.isArray(post.author) ? post.author[0]?.name : (post.author as any)?.name || "Krishna Naturals";

    return (
        <div style={{ paddingTop: "6rem", minHeight: "100vh", background: "var(--cream)" }}>
            <div className="max-w-4xl mx-auto px-6 py-12">
                <Link href="/blog" className="inline-flex items-center gap-2 text-[var(--forest)] hover:underline mb-8 font-semibold">
                    <ArrowLeft size={16} /> Back to all articles
                </Link>

                <h1 className="text-4xl md:text-5xl font-bold mb-6" style={{ fontFamily: "'Playfair Display', serif", color: "var(--forest-dark)" }}>
                    {post.title}
                </h1>

                <div className="flex flex-wrap items-center gap-6 text-gray-500 mb-10 pb-6 border-b border-gray-200">
                    <div className="flex items-center gap-2">
                        <User size={18} />
                        <span>By {authorName}</span>
                    </div>
                    <div className="flex items-center gap-2">
                        <Calendar size={18} />
                        <span>{new Date(post.published_at).toLocaleDateString("en-US", { year: 'numeric', month: 'long', day: 'numeric' })}</span>
                    </div>
                </div>

                {post.image_url && (
                    <div className="mb-12 rounded-2xl overflow-hidden shadow-lg h-[400px] md:h-[500px] relative">
                        <Image
                            src={post.image_url}
                            alt={post.title}
                            fill
                            className="object-cover"
                            sizes="(max-w-width: 800px) 100vw, 800px"
                            priority
                        />
                    </div>
                )}

                <article className="prose prose-lg max-w-none text-gray-800" dangerouslySetInnerHTML={{ __html: post.content }} />

                {/* Related Posts Section */}
                {relatedPosts && relatedPosts.length > 0 && (
                    <div className="mt-20 pt-16 border-t border-gray-200">
                        <h3 className="text-3xl font-bold mb-8" style={{ fontFamily: "'Playfair Display', serif", color: "var(--forest-dark)" }}>
                            More articles you might like
                        </h3>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                            {relatedPosts.map((relatedPost) => (
                                <Link href={`/blog/${relatedPost.slug}`} key={relatedPost.slug} className="group cursor-pointer">
                                    <div className="w-full h-48 bg-gray-200 relative mb-4 overflow-hidden rounded-xl">
                                        {relatedPost.image_url && (
                                            <Image
                                                src={relatedPost.image_url}
                                                alt={relatedPost.title}
                                                fill
                                                className="object-cover transition-transform duration-500 group-hover:scale-105"
                                            />
                                        )}
                                    </div>
                                    <p className="text-xs text-gray-500 mb-2">{new Date(relatedPost.published_at).toLocaleDateString()}</p>
                                    <h4 className="font-bold text-lg mb-2 group-hover:text-[var(--forest)] transition-colors line-clamp-2" style={{ color: "var(--forest-dark)" }}>
                                        {relatedPost.title}
                                    </h4>
                                </Link>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

