"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { CheckCircle2 } from "lucide-react";
import { auth } from "@/lib/firebase/config";
import { onAuthStateChanged } from "firebase/auth";
import { createClient } from "@/lib/supabase/client";
import { toast } from "react-hot-toast";
import { useCartStore } from "@/store/cartStore";

export default function CheckoutPage() {
    const [isSuccess, setIsSuccess] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [user, setUser] = useState<any>(null);
    const [isCodEnabled, setIsCodEnabled] = useState(true);
    const supabase = createClient();

    // Form State
    const [formData, setFormData] = useState({
        firstName: "",
        lastName: "",
        email: "",
        phone: "",
        address: "",
        city: "",
        state: "",
        postalCode: ""
    });

    const [paymentMethod, setPaymentMethod] = useState("razorpay");

    useEffect(() => {
        // Load Razorpay Script
        const script = document.createElement("script");
        script.src = "https://checkout.razorpay.com/v1/checkout.js";
        script.async = true;
        document.body.appendChild(script);

        // Get Saved Shipping Info
        if (typeof window !== "undefined") {
            const savedInfo = localStorage.getItem("kn_shipping_info");
            if (savedInfo) {
                try {
                    const parsed = JSON.parse(savedInfo);
                    setFormData(prev => ({ ...prev, ...parsed }));
                } catch (e) {
                    // Ignore parse errors
                }
            }
        }

        // Get Auth User
        const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
            if (currentUser) {
                setUser(currentUser);
                setFormData(prev => ({ ...prev, email: currentUser.email || "" }));
            }
        });

        // Fetch Store Settings
        const fetchSettings = async () => {
            const { data } = await supabase.from('store_settings').select('cod_enabled').single();
            if (data && data.cod_enabled === false) {
                setIsCodEnabled(false);
                setPaymentMethod("razorpay"); // Force Razorpay if COD disabled
            }
        };
        fetchSettings();

        return () => {
            if (document.body.contains(script)) {
                document.body.removeChild(script);
            }
            unsubscribe();
        };
    }, []);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const newFormData = { ...formData, [e.target.name]: e.target.value };
        setFormData(newFormData);

        // Save shipping details as they are typed
        if (typeof window !== "undefined") {
            // Dont save the email automatically as it's enforced by the auth session
            const { email, ...addressInfo } = newFormData;
            localStorage.setItem("kn_shipping_info", JSON.stringify(addressInfo));
        }
    };

    const cartItems = useCartStore((state) => state.items);
    const cartTotal = useCartStore((state) => state.getTotalPrice());
    const clearCart = useCartStore((state) => state.clearCart);

    const handleCheckout = async () => {
        // Check if user is logged in
        if (!user) {
            toast.error("Please log in to complete your checkout.");
            return;
        }

        // Check if cart has items
        if (cartItems.length === 0) {
            toast.error("Your cart is empty. Please add items to proceed.");
            return;
        }

        // Validate that cart items have valid UUIDs (prevents legacy localstorage data from crashing the DB checkout)
        const isValidUUID = (id: string) => /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(id);
        const hasLegacyItems = cartItems.some(item => !isValidUUID(item.id));
        if (hasLegacyItems) {
            clearCart();
            toast.error("Your cart contained outdated items and has been refreshed. Please add the products again.");
            return;
        }

        // Basic Validation
        if (!formData.firstName || !formData.address || !formData.city || !formData.phone || !formData.state || !formData.postalCode) {
            toast.error("Please fill in all shipping details.");
            return;
        }

        setIsLoading(true);

        if (paymentMethod === "cod") {
            await finalizeOrder("COD", "pending");
            return;
        }

        try {
            // STEP 1: Create Order via our Backend API
            const res = await fetch("/api/razorpay/create-order", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ amount: cartTotal })
            });
            const orderData = await res.json();

            if (!res.ok) throw new Error(orderData.error);

            // STEP 2: Open Razorpay Checkout Modal
            const options = {
                key: process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID || 'rzp_test_YourKeyIdHere',
                amount: orderData.amount,
                currency: orderData.currency,
                name: "Krishna Naturals",
                description: "Purchase of Pure Honey",
                image: window.location.origin + "/images/logo.png",
                order_id: orderData.id,
                handler: async function (response: any) {
                    // STEP 3: Verify Payment Signature via Backend
                    const verifyRes = await fetch("/api/razorpay/verify-payment", {
                        method: "POST",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify({
                            razorpay_order_id: response.razorpay_order_id,
                            razorpay_payment_id: response.razorpay_payment_id,
                            razorpay_signature: response.razorpay_signature
                        })
                    });

                    const verifyData = await verifyRes.json();

                    if (verifyData.success) {
                        toast.success("Payment Successful!");
                        await finalizeOrder(
                            "Razorpay",
                            "processing",
                            response.razorpay_order_id,
                            response.razorpay_payment_id,
                            response.razorpay_signature
                        );
                    } else {
                        toast.error("Payment Verification Failed!");
                        setIsLoading(false);
                    }
                },
                prefill: {
                    name: `${formData.firstName} ${formData.lastName}`,
                    email: formData.email,
                    contact: formData.phone
                },
                theme: {
                    color: "#2C4A3B" // Forest green
                }
            };

            const rzp = new (window as any).Razorpay(options);

            rzp.on('payment.failed', function (response: any) {
                toast.error(`Payment failed: ${response.error.description || "Unknown error"}`);
                setIsLoading(false);
            });

            rzp.open();
        } catch (error) {
            console.error(error);
            toast.error("Error initiating payment. Please try again or use COD.");
            setIsLoading(false);
        }
    };

    const finalizeOrder = async (method: string, status: string, rzpOrderId?: string, rzpPaymentId?: string, rzpSignature?: string) => {
        const orderNumber = `ORD-${Math.floor(Math.random() * 1000000)}`;

        const { data: newOrder, error } = await supabase
            .from("orders")
            .insert({
                user_id: user.uid,
                subtotal: cartTotal,
                total: cartTotal,
                status: status,
                order_number: orderNumber,
                shipping_name: `${formData.firstName} ${formData.lastName}`.trim(),
                shipping_phone: formData.phone,
                shipping_address_line1: formData.address,
                shipping_city: formData.city,
                shipping_state: formData.state,
                shipping_pincode: formData.postalCode,
                razorpay_order_id: rzpOrderId || null,
                razorpay_payment_id: rzpPaymentId || null,
                razorpay_signature: rzpSignature || null
            })
            .select()
            .single();

        if (error || !newOrder) {
            console.error("Supabase order error:", JSON.stringify(error, null, 2));
            toast.error("Failed to save order to database.");
        } else {
            // Save Order Items
            const orderItemsPayload = cartItems.map(item => ({
                order_id: newOrder.id,
                product_id: item.id,
                product_name: item.name,
                product_image: item.image,
                quantity: item.quantity,
                price: item.price,
                total: item.price * item.quantity
            }));

            const { error: itemsError } = await supabase.from("order_items").insert(orderItemsPayload);

            if (itemsError) {
                console.error("Failed to save order items:", itemsError);
            }

            setIsSuccess(true);
            clearCart();
        }
        setIsLoading(false);
    };

    if (isSuccess) {
        return (
            <div style={{ paddingTop: "6rem", minHeight: "100vh", background: "var(--cream)" }}>
                <div className="max-w-2xl mx-auto px-6 py-20 text-center">
                    <CheckCircle2 className="w-20 h-20 text-green-500 mx-auto mb-6" />
                    <h1 className="text-4xl font-bold mb-4" style={{ fontFamily: "'Playfair Display', serif", color: "var(--forest-dark)" }}>
                        Order Confirmed!
                    </h1>
                    <p className="text-gray-600 mb-8 text-lg">
                        Thank you for your purchase. We have received your order and will send you an email with shipping details shortly.
                    </p>
                    <div className="flex justify-center gap-4">
                        <Link href="/orders" className="px-6 py-3 rounded-full text-white font-medium transition-transform hover:-translate-y-0.5" style={{ background: "var(--forest-dark)" }}>
                            View Orders
                        </Link>
                        <Link href="/shop" className="px-6 py-3 rounded-full font-medium transition-transform hover:-translate-y-0.5 border" style={{ borderColor: "var(--forest)", color: "var(--forest)" }}>
                            Continue Shopping
                        </Link>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div style={{ paddingTop: "6rem", minHeight: "100vh", background: "var(--cream)" }}>
            <div className="max-w-6xl mx-auto px-6 py-12">
                <h1 className="text-4xl font-bold mb-10" style={{ fontFamily: "'Playfair Display', serif", color: "var(--forest-dark)" }}>
                    Checkout
                </h1>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
                    {/* Shipping Form */}
                    <div className="bg-white p-8 rounded-2xl border border-gray-100 shadow-sm">
                        <h2 className="text-xl font-bold mb-6" style={{ color: "var(--forest-dark)" }}>Shipping Details</h2>
                        <form className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">First Name <span className="text-red-500">*</span></label>
                                    <input type="text" name="firstName" value={formData.firstName} onChange={handleChange} className="w-full px-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)]" />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Last Name</label>
                                    <input type="text" name="lastName" value={formData.lastName} onChange={handleChange} className="w-full px-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)]" />
                                </div>
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Email <span className="text-red-500">* (Logged In)</span></label>
                                    <input type="email" name="email" value={formData.email} disabled className="w-full px-4 py-2 border border-gray-200 bg-gray-50 rounded-lg text-gray-500 cursor-not-allowed" />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Phone Number <span className="text-red-500">*</span></label>
                                    <input type="tel" name="phone" value={formData.phone} onChange={handleChange} className="w-full px-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)]" />
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Street Address <span className="text-red-500">*</span></label>
                                <input type="text" name="address" value={formData.address} onChange={handleChange} className="w-full px-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)]" />
                            </div>
                            <div className="grid grid-cols-3 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">City <span className="text-red-500">*</span></label>
                                    <input type="text" name="city" value={formData.city} onChange={handleChange} className="w-full px-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)]" />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">State <span className="text-red-500">*</span></label>
                                    <input type="text" name="state" value={formData.state} onChange={handleChange} className="w-full px-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)]" />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">ZIP Code <span className="text-red-500">*</span></label>
                                    <input type="text" name="postalCode" value={formData.postalCode} onChange={handleChange} className="w-full px-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)]" />
                                </div>
                            </div>
                        </form>

                        <h2 className="text-xl font-bold mt-10 mb-6" style={{ color: "var(--forest-dark)" }}>Payment Method</h2>
                        <div className="space-y-3">
                            <label className={`flex items-center gap-3 p-4 border rounded-xl cursor-pointer hover:bg-gray-50 transition-colors ${paymentMethod === 'razorpay' ? 'border-[var(--forest)] bg-green-50/30' : 'border-gray-200'}`}>
