"use client";

import { useState, useEffect } from "react";
import { Mail, Phone, MapPin, Send } from "lucide-react";
import { createClient } from "@/lib/supabase/client";
import { auth } from "@/lib/firebase/config";
import { onAuthStateChanged } from "firebase/auth";
import { toast } from "react-hot-toast";

export default function ContactPage() {
    const supabase = createClient();
    const [user, setUser] = useState<any>(null);
    const [isSubmitting, setIsSubmitting] = useState(false);

    const [formData, setFormData] = useState({
        name: "",
        email: "",
        subject: "",
        message: ""
    });

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
            setUser(currentUser);
            if (currentUser) {
                setFormData(prev => ({ ...prev, email: currentUser.email || "" }));
            }
        });
        return () => unsubscribe();
    }, []);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!formData.name || !formData.email || !formData.subject || !formData.message) {
            return toast.error("Please fill in all fields");
        }

        setIsSubmitting(true);

        const { error } = await supabase
            .from("support_tickets")
            .insert({
                user_id: user ? user.uid : null,
                guest_email: user ? null : formData.email,
                subject: `[${formData.name}] - ${formData.subject}`,
                message: formData.message,
                status: 'open'
            });

        setIsSubmitting(false);

        if (error) {
            console.error(error);
            toast.error("Failed to send message. Please try again later.");
        } else {
            toast.success("Message sent successfully! We will get back to you soon.");
            setFormData({ name: "", email: user?.email || "", subject: "", message: "" });
        }
    };

    return (
        <div style={{ paddingTop: "6rem", minHeight: "100vh", background: "var(--cream)" }}>
            <div className="text-center py-20 px-6 grain-overlay" style={{ background: "var(--forest-dark)", position: "relative" }}>
                <div className="relative z-10 max-w-2xl mx-auto">
                    <p className="text-xs font-bold uppercase tracking-[0.2em] mb-4 mt-8" style={{ color: "var(--gold)" }}>Get in Touch</p>
                    <h1 className="text-4xl md:text-5xl font-bold mb-4" style={{ fontFamily: "'Playfair Display', serif", color: "var(--cream)" }}>
                        Contact Us
                    </h1>
                    <p style={{ color: "rgba(253,250,243,0.5)" }}>
                        Whether you have a question about our products, pricing, or anything else, our team is ready to answer all your questions.
                    </p>
                </div>
            </div>

            <div className="max-w-5xl mx-auto px-6 py-20">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                    {/* Contact Info */}
                    <div className="space-y-8">
                        <div>
                            <h2 className="text-2xl font-bold mb-6" style={{ fontFamily: "'Playfair Display', serif", color: "var(--forest-dark)" }}>Our Office</h2>
                            <div className="flex items-start gap-4 mb-4">
                                <MapPin className="text-[var(--gold-dark)] mt-1" />
                                <div>
                                    <h3 className="font-bold text-gray-900">Address</h3>
                                    <p className="text-gray-600">Madhapar, Bhuj<br />Gujarat - 370020, India</p>
                                </div>
                            </div>
                        </div>
                        <div>
                            <div className="flex items-start gap-4 mb-4">
                                <Phone className="text-[var(--gold-dark)] mt-1" />
                                <div>
                                    <h3 className="font-bold text-gray-900">Phone</h3>
                                    <p className="text-gray-600">+91 94087 24778</p>
                                </div>
                            </div>
                        </div>
                        <div>
                            <div className="flex items-start gap-4 mb-4">
                                <Mail className="text-[var(--gold-dark)] mt-1" />
                                <div>
                                    <h3 className="font-bold text-gray-900">Email</h3>
                                    <a href="mailto:info.krishnanaturals@gmail.com" className="text-gray-600 hover:text-[var(--forest)] transition-colors">
                                        info.krishnanaturals@gmail.com
                                    </a>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Contact Form */}
                    <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
                        <h2 className="text-2xl font-bold mb-6" style={{ fontFamily: "'Playfair Display', serif", color: "var(--forest-dark)" }}>Send us a message</h2>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Name</label>
                                <input
                                    name="name"
                                    value={formData.name}
                                    onChange={handleChange}
                                    type="text"
                                    className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-[var(--forest)] outline-none"
                                    placeholder="Your name"
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                                    <input
                                        name="email"
                                        value={formData.email}
                                        onChange={handleChange}
                                        type="email"
                                        disabled={!!user}
                                        className={`w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-[var(--forest)] outline-none ${user ? 'bg-gray-100' : ''}`}
                                        placeholder="your@email.com"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Subject</label>
                                    <input
                                        name="subject"
                                        value={formData.subject}
                                        onChange={handleChange}
                                        type="text"
                                        className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-[var(--forest)] outline-none"
                                        placeholder="Order issue..."
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Message</label>
                                <textarea
                                    name="message"
                                    value={formData.message}
                                    onChange={handleChange}
                                    rows={4}
                                    className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-[var(--forest)] outline-none"
                                    placeholder="How can we help you?"
                                ></textarea>
                            </div>
                            <button
                                type="submit"
                                disabled={isSubmitting}
                                className={`w-full py-3 rounded-full text-white font-medium flex items-center justify-center gap-2 transition-transform hover:-translate-y-0.5 ${isSubmitting ? 'opacity-70' : ''}`}
                                style={{ background: "var(--forest-dark)" }}
                            >
                                {isSubmitting ? "Sending..." : "Send Message"}
                            </button>
                        </form>
                    </div>
                </div>
            </div>
        </div>
    );
}

