"use client";

import { useEffect, useState } from "react";
import { auth } from "@/lib/firebase/config";
import { onAuthStateChanged, signOut } from "firebase/auth";
import { User, Package, MapPin, LogOut, Plus, Trash2, CheckCircle2 } from "lucide-react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import { toast } from "react-hot-toast";

export default function ProfilePage() {
    const [user, setUser] = useState<any>(null);
    const [firstName, setFirstName] = useState("");
    const [lastName, setLastName] = useState("");
    const [isSaving, setIsSaving] = useState(false);

    // Address State
    const [addresses, setAddresses] = useState<any[]>([]);
    const [showAddressForm, setShowAddressForm] = useState(false);
    const [newAddress, setNewAddress] = useState({
        address_line_1: "", city: "", state: "", postal_code: "", phone: ""
    });

    const router = useRouter();
    const supabase = createClient();

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
            if (currentUser) {
                setUser(currentUser);

                // Fetch existing profile data
                const { data: profile } = await supabase
                    .from("profiles")
                    .select("first_name, last_name")
                    .eq("id", currentUser.uid)
                    .single();

                if (profile) {
                    setFirstName(profile.first_name || "");
                    setLastName(profile.last_name || "");
                } else {
                    await supabase.from("profiles").insert({ id: currentUser.uid });
                }

                // Fetch Addresses
                fetchAddresses(currentUser.uid);

            } else {
                router.push("/auth/login");
            }
        });
        return () => unsubscribe();
    }, [router, supabase]);

    const fetchAddresses = async (uid: string) => {
        const { data } = await supabase
            .from("addresses")
            .select("*")
            .eq("user_id", uid)
            .order("is_default", { ascending: false });
        if (data) setAddresses(data);
    };

    const handleSaveProfile = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;
        setIsSaving(true);
        const { error } = await supabase
            .from("profiles")
            .update({ first_name: firstName, last_name: lastName })
            .eq("id", user.uid);

        setIsSaving(false);
        if (error) {
            toast.error("Failed to save profile.");
        } else {
            toast.success("Profile saved successfully!");
        }
    };

    const handleSaveAddress = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;

        const isFirst = addresses.length === 0;

        const { error } = await supabase.from("addresses").insert({
            user_id: user.uid,
            is_default: isFirst,
            ...newAddress
        });

        if (error) {
            toast.error("Failed to save address.");
        } else {
            toast.success("Address added.");
            setShowAddressForm(false);
            setNewAddress({ address_line_1: "", city: "", state: "", postal_code: "", phone: "" });
            fetchAddresses(user.uid);
        }
    };

    const handleDeleteAddress = async (id: string) => {
        await supabase.from("addresses").delete().eq("id", id);
        fetchAddresses(user.uid);
        toast.success("Address removed.");
    };

    const handleSetDefault = async (id: string) => {
        // Reset all to false
        await supabase.from("addresses").update({ is_default: false }).eq("user_id", user.uid);
        // Set new default
        await supabase.from("addresses").update({ is_default: true }).eq("id", id);

        fetchAddresses(user.uid);
        toast.success("Default address updated.");
    };

    const handleSignOut = async () => {
        await signOut(auth);
        await fetch('/api/auth/session', { method: 'DELETE' });
        router.push("/");
    };

    if (!user) return <div className="min-h-screen pt-32 text-center text-gray-500">Loading profile...</div>;

    return (
        <div style={{ paddingTop: "6rem", minHeight: "100vh", background: "var(--cream)" }}>
            <div className="max-w-5xl mx-auto px-6 py-12">
                <div className="flex flex-col md:flex-row gap-12">

                    {/* Sidebar */}
                    <div className="w-full md:w-64 shrink-0">
                        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 flex flex-col items-center text-center">
                            <div className="w-20 h-20 bg-[var(--forest)] text-white rounded-full flex items-center justify-center text-2xl font-bold mb-4">
                                {user.email?.charAt(0).toUpperCase()}
                            </div>
                            <h2 className="font-bold text-lg text-gray-900 break-all">{user.email}</h2>
                            <p className="text-xs text-green-600 font-bold uppercase tracking-wider mt-2 bg-green-50 px-3 py-1 rounded-full">
                                Verified Customer
                            </p>
                        </div>

                        <div className="mt-6 bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                            <Link href="/profile" className="flex items-center gap-3 px-6 py-4 border-b border-gray-50 hover:bg-gray-50 font-medium text-[var(--forest-dark)] bg-gray-50">
                                <User size={18} /> Account Details
                            </Link>
                            <Link href="/orders" className="flex items-center gap-3 px-6 py-4 border-b border-gray-50 hover:bg-gray-50 font-medium text-gray-600">
                                <Package size={18} /> My Orders
                            </Link>
                            <Link href="/profile#addresses" className="flex items-center gap-3 px-6 py-4 border-b border-gray-50 hover:bg-gray-50 font-medium text-gray-600">
                                <MapPin size={18} /> Addresses
                            </Link>
                            <button onClick={handleSignOut} className="w-full flex items-center gap-3 px-6 py-4 hover:bg-red-50 font-medium text-red-600 transition-colors text-left">
                                <LogOut size={18} /> Sign Out
                            </button>
                        </div>
                    </div>

                    {/* Main Content Area */}
                    <div className="flex-grow space-y-8">
                        {/* Profile Info */}
                        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-8">
                            <h1 className="text-3xl font-bold mb-8" style={{ fontFamily: "'Playfair Display', serif", color: "var(--forest-dark)" }}>
                                Account Details
                            </h1>

                            <form onSubmit={handleSaveProfile} className="space-y-6 max-w-xl">
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                                    <div>
                                        <label className="block text-sm font-medium text-gray-700 mb-1">First Name</label>
                                        <input
                                            type="text"
                                            value={firstName}
                                            onChange={(e) => setFirstName(e.target.value)}
                                            className="w-full px-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)] disabled:opacity-50"
                                            disabled={isSaving}
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-gray-700 mb-1">Last Name</label>
                                        <input
                                            type="text"
                                            value={lastName}
                                            onChange={(e) => setLastName(e.target.value)}
                                            className="w-full px-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-[var(--forest)] disabled:opacity-50"
                                            disabled={isSaving}
                                        />
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Email <span className="text-green-600 text-xs ml-2">(Verified)</span></label>
                                    <input type="email" value={user.email} disabled className="w-full px-4 py-2 border border-gray-200 bg-gray-50 rounded-lg text-gray-500 cursor-not-allowed" />
                                </div>
                                <button
                                    type="submit"
                                    disabled={isSaving}
                                    className="px-8 py-3 rounded-full text-white font-medium transition-transform hover:-translate-y-0.5 disabled:opacity-70 disabled:hover:translate-y-0"
                                    style={{ background: "var(--forest)" }}
                                >
                                    {isSaving ? "Saving..." : "Save Changes"}
                                </button>
                            </form>
                        </div>

                        {/* Addresses Section */}
                        <div id="addresses" className="bg-white rounded-2xl shadow-sm border border-gray-100 p-8 pt-10 border-t-4 border-t-[var(--forest)]">
                            <div className="flex justify-between items-center mb-8">
                                <h2 className="text-2xl font-bold" style={{ fontFamily: "'Playfair Display', serif", color: "var(--forest-dark)" }}>
                                    Saved Addresses
                                </h2>
                                {!showAddressForm && (
                                    <button
                                        onClick={() => setShowAddressForm(true)}
                                        className="flex items-center gap-2 text-sm font-semibold px-4 py-2 rounded-lg border border-gray-200 hover:bg-gray-50 transition-colors"
                                        style={{ color: "var(--forest-dark)" }}
                                    >
                                        <Plus size={16} /> Add New
                                    </button>
                                )}
                            </div>

                            {/* Address List */}
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                                {addresses.map((addr) => (
                                    <div key={addr.id} className={`p-5 rounded-xl border relative transition-colors ${addr.is_default ? 'border-[var(--forest)] bg-green-50/20' : 'border-gray-200 hover:border-gray-300'}`}>
                                        {addr.is_default && (
                                            <span className="absolute top-4 right-4 text-[var(--forest)] flex items-center gap-1 text-xs font-bold uppercase tracking-wider">
                                                <CheckCircle2 size={14} /> Default
                                            </span>
                                        )}
                                        <p className="font-semibold text-gray-900 mb-1">{addr.address_line_1}</p>
                                        <p className="text-gray-600 text-sm mb-1">{addr.city}, {addr.state} {addr.postal_code}</p>
                                        <p className="text-gray-500 text-sm mb-4">Phone: {addr.phone}</p>

                                        <div className="flex gap-4 pt-3 border-t border-gray-100/50">
                                            {!addr.is_default && (
                                                <button onClick={() => handleSetDefault(addr.id)} className="text-xs font-semibold text-[var(--forest)] hover:underline">
                                                    Make Default
                                                </button>
                                            )}
                                            <button onClick={() => handleDeleteAddress(addr.id)} className="text-xs font-semibold text-red-500 hover:underline flex items-center gap-1">
                                                <Trash2 size={12} /> Remove
                                            </button>
                                        </div>
                                    </div>
                                ))}

                                {addresses.length === 0 && !showAddressForm && (
                                    <div className="col-span-full py-8 text-center bg-gray-50 rounded-xl border border-dashed border-gray-200">
                                        <p className="text-gray-500 text-sm">You have no saved addresses.</p>
                                    </div>
                                )}
                            </div>

                            {/* Add Address Form */}
                            {showAddressForm && (
                                <form onSubmit={handleSaveAddress} className="bg-gray-50 p-6 rounded-xl border border-gray-200 animate-in fade-in slide-in-from-top-4">
                                    <h3 className="font-bold text-gray-900 mb-4">Add a new address</h3>
                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-4">
                                        <div className="sm:col-span-2">
                                            <input type="text" required placeholder="Street Address" className="w-full px-3 py-2 border border-gray-200 rounded-md text-sm outline-none focus:border-[var(--forest)]"
                                                value={newAddress.address_line_1} onChange={e => setNewAddress({ ...newAddress, address_line_1: e.target.value })} />
                                        </div>
                                        <div>
                                            <input type="text" required placeholder="City" className="w-full px-3 py-2 border border-gray-200 rounded-md text-sm outline-none focus:border-[var(--forest)]"
                                                value={newAddress.city} onChange={e => setNewAddress({ ...newAddress, city: e.target.value })} />
                                        </div>
                                        <div>
                                            <input type="text" required placeholder="State / Province" className="w-full px-3 py-2 border border-gray-200 rounded-md text-sm outline-none focus:border-[var(--forest)]"
                                                value={newAddress.state} onChange={e => setNewAddress({ ...newAddress, state: e.target.value })} />
                                        </div>
                                        <div>
                                            <input type="text" required placeholder="Postal / Zip Code" className="w-full px-3 py-2 border border-gray-200 rounded-md text-sm outline-none focus:border-[var(--forest)]"
                                                value={newAddress.postal_code} onChange={e => setNewAddress({ ...newAddress, postal_code: e.target.value })} />
                                        </div>
                                        <div>
                                            <input type="tel" required placeholder="Phone Number" className="w-full px-3 py-2 border border-gray-200 rounded-md text-sm outline-none focus:border-[var(--forest)]"
                                                value={newAddress.phone} onChange={e => setNewAddress({ ...newAddress, phone: e.target.value })} />
                                        </div>
                                    </div>
                                    <div className="flex gap-3 mt-6">
                                        <button type="submit" className="px-5 py-2 rounded-lg text-white font-medium text-sm transition-colors" style={{ background: "var(--forest)" }}>
                                            Save Address
                                        </button>
                                        <button type="button" onClick={() => setShowAddressForm(false)} className="px-5 py-2 rounded-lg border border-gray-300 text-gray-700 bg-white font-medium text-sm hover:bg-gray-50">
                                            Cancel
                                        </button>
                                    </div>
                                </form>
                            )}
                        </div>

                    </div>

                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { MessageCircle, X, Send, Bot, User } from "lucide-react";
import { createClient } from "@/lib/supabase/client";

type Message = {
    id: string;
    text: string;
    sender: "user" | "bot";
    timestamp: Date;
};

export default function ChatBot() {
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState<Message[]>([
        {
            id: "welcome",
            text: "Hi there! I'm Krishna, your AI assistant. How can I help you today? (You can ask about products or track your order by replying with 'Track ORD-XXXXX')",
            sender: "bot",
            timestamp: new Date()
        }
    ]);
    const [input, setInput] = useState("");
    const [isTyping, setIsTyping] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const supabase = createClient();

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        if (isOpen) {
            scrollToBottom();
        }
    }, [messages, isOpen]);

    const handleSend = async (e?: React.FormEvent) => {
        e?.preventDefault();
        if (!input.trim()) return;

        const userMsg: Message = {
            id: Date.now().toString(),
            text: input,
            sender: "user",
            timestamp: new Date()
        };

        setMessages(prev => [...prev, userMsg]);
        setInput("");
        setIsTyping(true);

        const lowerInput = userMsg.text.toLowerCase();
        let botReply = "I'm still learning! For detailed support, please contact us at support@krishnanaturals.co.in.";

        // Order Tracking Logic
        if (lowerInput.includes("track")) {
            const orderMatch = userMsg.text.match(/ORD-\d+/i);
            if (orderMatch) {
                const orderId = orderMatch[0].toUpperCase();
                const { data, error } = await supabase
                    .from("orders")
                    .select("status, tracking_url")
                    .eq("order_id", orderId)
                    .single();

                if (data) {
                    botReply = `Your order ${orderId} is currently: **${data.status.toUpperCase()}**.`;
                    if (data.tracking_url) {
                        botReply += ` You can track it here: ${data.tracking_url}`;
                    }
                } else {
                    botReply = `I couldn't find an order matching ${orderId}. Please check the ID and try again.`;
                }
            } else {
                botReply = "To track an order, please provide your Order ID (e.g., 'Track ORD-12345').";
            }
        }
        // Site Helping Logic
        else if (lowerInput.includes("honey") || lowerInput.includes("price") || lowerInput.includes("buy")) {
            botReply = "We sell 100% pure, raw forest honey natively sourced in India. We have sizes ranging from 250g to 1kg starting at Γé╣349. Head over to our Shop page to browse our collection!";
        } else if (lowerInput.includes("delivery") || lowerInput.includes("shipping")) {
            botReply = "We offer FREE delivery on all orders above Γé╣500! Standard delivery takes 3-5 business days.";
        } else if (lowerInput.includes("hello") || lowerInput.includes("hi")) {
            botReply = "Namaste! How can I assist you in finding the purest honey today?";
        }

        // Simulate network delay
        setTimeout(() => {
            setMessages(prev => [...prev, {
                id: (Date.now() + 1).toString(),
                text: botReply,
                sender: "bot",
                timestamp: new Date()
            }]);
            setIsTyping(false);
        }, 1200);
    };

    return (
        <div className="fixed bottom-6 right-6 z-50">
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0, y: 20, scale: 0.95 }}
                        animate={{ opacity: 1, y: 0, scale: 1 }}
                        exit={{ opacity: 0, y: 20, scale: 0.95 }}
                        transition={{ duration: 0.2 }}
                        className="absolute bottom-20 right-0 w-[350px] sm:w-[400px] h-[500px] bg-white rounded-2xl shadow-2xl flex flex-col border border-gray-100 overflow-hidden"
                    >
                        {/* Header */}
                        <div className="p-4" style={{ background: "var(--forest-dark)", color: "var(--cream)" }}>
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 rounded-full flex items-center justify-center bg-white/10">
                                        <Bot size={24} style={{ color: "var(--gold)" }} />
                                    </div>
                                    <div>
                                        <h3 className="font-bold text-sm">Krishna Assistant</h3>
                                        <div className="flex items-center gap-1.5 mt-0.5">
                                            <div className="w-2 h-2 rounded-full bg-green-400 animate-pulse"></div>
                                            <span className="text-xs text-white/70">Online & Ready to Help</span>
                                        </div>
                                    </div>
                                </div>
                                <button onClick={() => setIsOpen(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors cursor-pointer">
                                    <X size={20} />
                                </button>
                            </div>
                        </div>

                        {/* Chat Messages Log */}
                        <div className="flex-1 p-4 overflow-y-auto bg-gray-50 flex flex-col gap-4">
                            {messages.map((msg) => (
                                <div key={msg.id} className={`flex gap-3 max-w-[85%] ${msg.sender === "user" ? "ml-auto flex-row-reverse" : "mr-auto"}`}>
                                    <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${msg.sender === "bot" ? "bg-amber-100 text-amber-700" : "bg-gray-200 text-gray-600"}`}>
                                        {msg.sender === "bot" ? <Bot size={16} /> : <User size={16} />}
                                    </div>
                                    <div className={`p-3 rounded-2xl text-sm leading-relaxed shadow-sm ${msg.sender === "user" ? "bg-amber-500 text-white rounded-tr-sm" : "bg-white text-gray-800 border border-gray-100 rounded-tl-sm"}`}>
                                        {msg.text}
                                    </div>
                                </div>
                            ))}
                            {isTyping && (
                                <div className="mr-auto flex gap-3 max-w-[85%] items-end">
                                    <div className="w-8 h-8 rounded-full flex items-center justify-center shrink-0 bg-amber-100 text-amber-700">
                                        <Bot size={16} />
                                    </div>
                                    <div className="p-4 rounded-2xl bg-white border border-gray-100 rounded-tl-sm flex gap-1 shadow-sm">
                                        <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: "0ms" }}></span>
                                        <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: "150ms" }}></span>
                                        <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: "300ms" }}></span>
                                    </div>
                                </div>
                            )}
                            <div ref={messagesEndRef} />
                        </div>

                        {/* Input Area */}
                        <form onSubmit={handleSend} className="p-4 bg-white border-t border-gray-100">
                            <div className="relative flex items-center">
                                <input
                                    type="text"
                                    value={input}
                                    onChange={(e) => setInput(e.target.value)}
                                    placeholder="Type your message..."
                                    className="w-full pl-4 pr-12 py-3 rounded-xl border border-gray-200 focus:outline-none focus:border-amber-400 focus:ring-2 focus:ring-amber-400/20 transition-all text-sm"
                                />
                                <button
                                    type="submit"
                                    disabled={!input.trim() || isTyping}
                                    className="absolute right-2 p-2 rounded-lg bg-amber-500 text-white disabled:opacity-50 disabled:bg-gray-200 disabled:text-gray-400 transition-colors shadow-sm cursor-pointer"
                                    style={input.trim() ? { background: "var(--forest)", color: "var(--cream)" } : {}}
                                >
                                    <Send size={16} />
                                </button>
                            </div>
                        </form>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Floating Action Button */}
            {!isOpen && (
                <button
                    onClick={() => setIsOpen(true)}
                    className="w-14 h-14 rounded-full flex items-center justify-center shadow-2xl cursor-pointer hover:scale-105 active:scale-95 transition-transform"
                    style={{ background: "linear-gradient(135deg, var(--forest), var(--forest-dark))", color: "var(--cream)" }}
                >
                    <MessageCircle size={28} />
                </button>
            )}
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import Image from "next/image";
import { usePathname } from "next/navigation";
import { motion, AnimatePresence } from "framer-motion";
import { ShoppingCart, User, Search, ChevronDown } from "lucide-react";
import { onAuthChange, signOut } from "@/lib/firebase/auth";
import type { User as FirebaseUser } from "firebase/auth";

const navLinks = [
    { href: "/", label: "Home" },
    { href: "/shop", label: "Shop" },
    { href: "/legacy", label: "Legacy" },
    { href: "/leadership", label: "Leadership" },
    { href: "/blog", label: "Blog" },
    { href: "/contact", label: "Contact" },
];

export default function Navbar() {
    const [scrolled, setScrolled] = useState(false);
    const [user, setUser] = useState<FirebaseUser | null>(null);
    const [showUserMenu, setShowUserMenu] = useState(false);
    const pathname = usePathname();

    useEffect(() => {
        const unsub = onAuthChange(setUser);
        const handleScroll = () => setScrolled(window.scrollY > 30);
        window.addEventListener("scroll", handleScroll, { passive: true });
        return () => {
            unsub();
            window.removeEventListener("scroll", handleScroll);
        };
    }, []);

    return (
        <>
            {/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ DESKTOP NAVBAR ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */}
            <motion.header
                initial={{ y: -100, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ duration: 0.7, ease: [0.22, 1, 0.36, 1] }}
                className="fixed top-0 left-0 right-0 z-50 hidden md:block"
            >
                {/* Outer wrapper with dynamic background */}
                <div
                    style={{
                        transition: "all 0.4s cubic-bezier(0.22,1,0.36,1)",
                        ...(scrolled
                            ? {
                                background: "rgba(253,250,243,0.85)",
                                backdropFilter: "blur(24px) saturate(200%)",
                                WebkitBackdropFilter: "blur(24px) saturate(200%)",
                                boxShadow: "0 1px 0 rgba(0,0,0,0.04), 0 4px 16px rgba(0,0,0,0.03)",
                            }
                            : {
                                background: "transparent",
                            }),
                    }}
                >
                    <nav
                        className="max-w-6xl mx-auto px-8 flex items-center justify-between"
                        style={{
                            height: scrolled ? "60px" : "72px",
                            transition: "height 0.4s cubic-bezier(0.22,1,0.36,1)",
                        }}
                    >
                        {/* ΓöÇΓöÇ Logo ΓöÇΓöÇ */}
                        <Link href="/" className="flex items-center gap-3 group">
                            <Image
                                src="/images/logo.png"
                                alt="Krishna Naturals Logo"
                                width={200}
                                height={60}
                                className="h-7 w-auto object-contain"
                            />
                        </Link>

                        {/* ΓöÇΓöÇ Center Nav Links ΓöÇΓöÇ */}
                        <div
                            className="flex items-center rounded-full px-1.5 py-1"
                            style={{
                                background: scrolled ? "var(--forest-muted)" : "rgba(26,58,42,0.04)",
                                transition: "background 0.3s ease",
                            }}
                        >
                            {navLinks.map((l) => {
                                const isActive = pathname === l.href;
                                return (
                                    <Link
                                        key={l.href}
                                        href={l.href}
                                        className="relative px-4 py-1.5 rounded-full text-[13px] font-medium"
                                        style={{
                                            color: isActive ? "var(--white)" : "var(--gray-600)",
                                            transition: "color 0.2s ease",
                                            zIndex: 1,
                                        }}
                                        onMouseEnter={(e) => {
                                            if (!isActive) e.currentTarget.style.color = "var(--forest)";
                                        }}
                                        onMouseLeave={(e) => {
                                            if (!isActive) e.currentTarget.style.color = "var(--gray-600)";
                                        }}
                                    >
                                        {isActive && (
                                            <motion.div
                                                layoutId="navPill"
                                                className="absolute inset-0 rounded-full"
                                                style={{ background: "var(--forest)", zIndex: -1 }}
                                                transition={{ type: "spring", stiffness: 380, damping: 30 }}
                                            />
                                        )}
                                        {l.label}
                                    </Link>
                                );
                            })}
                        </div>

                        {/* ΓöÇΓöÇ Right Actions ΓöÇΓöÇ */}
                        <div className="flex items-center gap-1">
                            <Link
                                href="/shop"
                                className="p-2 rounded-xl flex items-center justify-center"
                                style={{ color: "var(--gray-500)", transition: "all 0.2s" }}
                                onMouseEnter={(e) => {
                                    e.currentTarget.style.color = "var(--forest)";
                                    e.currentTarget.style.background = "var(--forest-muted)";
                                }}
                                onMouseLeave={(e) => {
                                    e.currentTarget.style.color = "var(--gray-500)";
                                    e.currentTarget.style.background = "transparent";
                                }}
                            >
                                <Search size={18} strokeWidth={1.8} />
                            </Link>
                            <Link
                                href="/cart"
                                className="p-2 rounded-xl flex items-center justify-center relative"
                                style={{ color: "var(--gray-500)", transition: "all 0.2s" }}
                                onMouseEnter={(e) => {
                                    e.currentTarget.style.color = "var(--forest)";
                                    e.currentTarget.style.background = "var(--forest-muted)";
                                }}
                                onMouseLeave={(e) => {
                                    e.currentTarget.style.color = "var(--gray-500)";
                                    e.currentTarget.style.background = "transparent";
                                }}
                            >
                                <ShoppingCart size={18} strokeWidth={1.8} />
                            </Link>

                            <div className="w-px h-5 mx-2" style={{ background: "var(--border-strong)" }} />

                            {user ? (
                                <div className="relative">
                                    <button
                                        onClick={() => setShowUserMenu(!showUserMenu)}
                                        className="flex items-center gap-1.5 px-2 py-1.5 rounded-xl cursor-pointer"
                                        style={{
                                            background: "none",
                                            border: "none",
                                            color: "var(--gray-600)",
                                            transition: "all 0.2s",
                                        }}
                                        onMouseEnter={(e) => {
                                            e.currentTarget.style.background = "var(--forest-muted)";
                                        }}
                                        onMouseLeave={(e) => {
                                            e.currentTarget.style.background = "transparent";
                                        }}
                                    >
                                        {user.photoURL ? (
                                            <img
                                                src={user.photoURL}
                                                alt=""
                                                className="w-7 h-7 rounded-full"
                                                style={{ border: "2px solid var(--gold)", boxShadow: "0 0 0 1px var(--white)" }}
                                            />
                                        ) : (
                                            <div
                                                className="w-7 h-7 rounded-full flex items-center justify-center text-[11px] font-bold"
                                                style={{ background: "var(--forest)", color: "var(--cream)" }}
                                            >
                                                {user.displayName?.[0] || user.email?.[0]?.toUpperCase() || "U"}
                                            </div>
                                        )}
                                        <ChevronDown size={12} style={{ opacity: 0.5 }} />
                                    </button>
                                    <AnimatePresence>
                                        {showUserMenu && (
                                            <>
                                                <div
                                                    className="fixed inset-0 z-40"
                                                    onClick={() => setShowUserMenu(false)}
                                                />
                                                <motion.div
                                                    initial={{ opacity: 0, y: 8, scale: 0.96 }}
                                                    animate={{ opacity: 1, y: 0, scale: 1 }}
                                                    exit={{ opacity: 0, y: 8, scale: 0.96 }}
                                                    transition={{ duration: 0.15 }}
                                                    className="absolute right-0 top-12 w-56 rounded-2xl overflow-hidden z-50"
                                                    style={{
                                                        background: "var(--white)",
                                                        boxShadow: "0 16px 48px rgba(0,0,0,0.12), 0 0 0 1px rgba(0,0,0,0.04)",
                                                    }}
                                                >
                                                    <div className="p-4" style={{ borderBottom: "1px solid var(--border)" }}>
                                                        <p className="text-sm font-semibold truncate" style={{ color: "var(--forest-dark)" }}>
                                                            {user.displayName || "User"}
                                                        </p>
                                                        <p className="text-[11px] truncate mt-0.5" style={{ color: "var(--gray-400)" }}>
                                                            {user.email}
                                                        </p>
                                                    </div>
                                                    <div className="py-1">
                                                        <Link href="/profile" className="block px-4 py-2.5 text-sm font-medium" style={{ color: "var(--gray-600)" }}>
                                                            My Profile
                                                        </Link>
                                                        <Link href="/orders" className="block px-4 py-2.5 text-sm font-medium" style={{ color: "var(--gray-600)" }}>
                                                            My Orders
                                                        </Link>
                                                    </div>
                                                    <div style={{ borderTop: "1px solid var(--border)" }}>
                                                        <button
                                                            onClick={() => { signOut(); setShowUserMenu(false); }}
                                                            className="w-full text-left px-4 py-2.5 text-sm font-medium cursor-pointer"
                                                            style={{ color: "#EF4444", background: "none", border: "none" }}
                                                        >
                                                            Sign Out
                                                        </button>
                                                    </div>
                                                </motion.div>
                                            </>
                                        )}
                                    </AnimatePresence>
                                </div>
                            ) : (
                                <Link
                                    href="/auth/login"
                                    className="btn btn-primary"
                                    style={{ padding: "0.5rem 1.25rem", fontSize: "13px", borderRadius: "0.75rem" }}
                                >
                                    Sign In
                                </Link>
                            )}
                        </div>
                    </nav>
                </div>
            </motion.header>

            {/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ MOBILE HEADER ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */}
            <motion.header
                initial={{ y: -60 }}
                animate={{ y: 0 }}
                transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
                className="fixed top-0 left-0 right-0 z-50 md:hidden"
                style={{
                    background: "rgba(253,250,243,0.9)",
                    backdropFilter: "blur(24px) saturate(200%)",
                    WebkitBackdropFilter: "blur(24px) saturate(200%)",
                    borderBottom: "1px solid rgba(0,0,0,0.04)",
                }}
            >
                <div
                    className="flex items-center justify-between px-5 max-w-lg mx-auto"
                    style={{ height: "56px" }}
                >
